// generated by rand_probe.py — random-stimulus cycle-exact equivalence
`timescale 1ns/1ps
module tb_rand;
    reg clk = 1'b0;
    reg rst;
    reg  [8:0] x;
    wire [1023:0] q;
    lgn_fsm dut (.clk(clk), .rst(rst), .x(x), .q(q));
    always #5 clk = ~clk;
    reg [8:0] stim [0:179];
    reg [1023:0] gold [0:179];
    integer r, t, errors;
    initial begin
        $readmemh("rand_stim.txt", stim);
        $readmemh("rand_gold.txt", gold);
        errors = 0;
        for (r = 0; r < 6; r = r + 1) begin
            rst = 1'b1; x = 9'b0;
            @(posedge clk); #1;
            if (q !== 1024') begin
                $display("RAND seq %0d: FAIL at reset", r);
                errors = errors + 1;
            end
            rst = 1'b0;
            for (t = 0; t < 30; t = t + 1) begin
                x = stim[r * 30 + t];
                @(posedge clk); #1;
                if (q !== gold[r * 30 + t]) begin
                    errors = errors + 1;
                    if (errors <= 5)
                        $display("RAND seq %0d: MISMATCH frame %0d", r, t);
                end
            end
        end
        if (errors == 0)
            $display("RAND: 6 seqs x 30 frames PASS");
        else
            $display("RAND: FAIL (%0d mismatches)", errors);
        $finish;
    end
endmodule
